+import { $internal } from '../../common';
+import type { Entity } from '../../entity/types';
+import { getEntityId } from '../../entity/utils/pack-entity';
+import type { Relation } from '../../relation/types';
+import type { Trait } from '../../trait/types';
+import type { World } from '../../world';
+import { checkQueryTracking } from './check-query-tracking';
+import type { PairTrackingGroup, QueryInstance } from '../types';
+
+const pairKey = (relation: Relation<Trait>, target: Entity) =>
+    `${relation[$internal].trait.id}:${target}`;
+
+export function trackPairEvent(
+    world: World,
+    entity: Entity,
+    relation: Relation<Trait>,
+    target: Entity,
+    type: 'add' | 'remove' | 'change'
+) {
+    const data = world[$internal].traitInstances[relation[$internal].trait.id];
+    if (!data) return;
+
+    const key = pairKey(relation, target);
+    for (const query of data.trackingQueries) {
+        if (!query.pairTrackingGroups.length) continue;
+        let touched = false;
+        for (const group of query.pairTrackingGroups) {
+            if (!group.pairs.some((pair) => {
+                const pairCtx = pair[$internal];
+                return pairCtx.relation === relation && (pairCtx.target === '*' || pairCtx.target === target);
+            })) continue;
+            touched = true;
+            updatePairGroup(group, entity, key, type);
+        }
+        if (!touched) continue;
+
+        const match = checkQueryTracking(world, query, entity, 'change', -1, 0) &&
+            query.pairTrackingGroups.every((group) => groupMatches(group, entity));
+        if (match) query.add(entity);
+        else query.remove(world, entity);
+    }
+}
+
+function updatePairGroup(group: PairTrackingGroup, entity: Entity, key: string, type: string) {
+    let events = group.events.get(entity);
+    if (!events) group.events.set(entity, (events = new Set()));
+    if (type === group.type) events.add(key);
+    else if ((type === 'add' && group.type === 'remove') || (type === 'remove' && group.type === 'add')) {
+        events.delete(key);
+    }
+}
+
+function groupMatches(group: PairTrackingGroup, entity: Entity) {
+    const events = group.events.get(entity);
+    if (!events?.size) return false;
+    if (group.logic === 'or') return true;
+    return group.pairs.every((pair) => {
+        const pairCtx = pair[$internal];
+        const prefix = `${pairCtx.relation[$internal].trait.id}:`;
+        return [...events].some((key) => key.startsWith(prefix) && (pairCtx.target === '*' || key === `${prefix}${pairCtx.target}`));
+    });
+}
+
+export function initializePairTracking(query: QueryInstance, world: World) {
+    for (const group of query.pairTrackingGroups) {
+        const snapshot = world[$internal].pairTrackingSnapshots.get(group.id);
+        if (!snapshot) continue;
+        for (const pair of group.pairs) {
+            const pairCtx = pair[$internal];
+            const prefix = `${pairCtx.relation[$internal].trait.id}:`;
+            for (const [key, entities] of snapshot) {
+                if (!key.startsWith(prefix) || (pairCtx.target !== '*' && key !== `${prefix}${pairCtx.target}`)) continue;
+                for (const entity of entities) {
+                    // A pair present now but absent from the factory snapshot was added.
+                    // Snapshot entries represent old state; current state is tested by callers.
+                    void entity;
+                }
+            }
+        }
+    }
+}
